        while(low<=high){
            int mid=(low+high)/2;
            if(arr[mid]==x){
                res2=mid;
                low=mid+1;
            }
            else if(x<arr[mid]){
                high=mid-1;
            }
            else{
                low=mid+1;
            }
        }
