        int mid = -1;

        ArrayList<Integer> list = new ArrayList<>();

        while(low <= high) {
            mid = (low + high) / 2;

            if(arr[mid] > x) high = mid - 1;
            else if(arr[mid] < x) low = mid + 1;
            else break;
        }

        if(mid == -1) {
            list.add(-1);
            list.add(-1);
            return list;
        }

