        int temp = mid;
        while(low <= high) {
            temp = (low + mid) / 2;

            if(arr[temp] > x) high = temp - 1;
            else if(arr[temp] < x) low = temp + 1;
            else high = temp - 1;
        }

        list.add(temp);

        high = arr.length - 1;
        while(mid <= high) {
            temp = (mid + high) / 2;

            if(arr[temp] > x) high = temp - 1;
            else if(arr[temp] < x) mid = temp + 1;
            else mid = temp + 1;
        }

        list.add(temp);

        return list;
    }
}

