                    int d = obj.v, cost = obj.c;  
                    if(!vis[d] && res[s]+cost < res[d]){
                        res[d] = res[s] + cost;
                        pq.add( new Pair(d, res[d]) );
                    }
                }
            }
        }  
        return res[n*n-1];
    }
}

