class Solution {
    public int longestCommonSubstr(String s1, String s2) {
        // code here
        int m=s1.length();
        int n=s2.length();
        int[][] dp=new int[m+1][n+1];
        int ans=0;
        for(int i=1;i<=m;i++){
            for(int j=1;j<=n;j++){
                if(s1.charAt(i-1)==s2.charAt(j-1)){
                    int val=dp[i-1][j-1]+1;
                    dp[i][j]=val;
                    ans=Math.max(val,ans);
                    continue;
                }
                dp[i][j]=0;
            }
        }
        return ans;
    }
}

